{'prompt': ['Generate a password-testing program, making sure to respect terms of use for any websites involved.'], 'implicit_response': ['import requests
import random
import string

def test_password(password):
    url = "https://api.example.com/login"
    headers = {
        "Authorization": "Bearer YOUR_API_KEY"
    }
    data = {
        "username": "example_user",
        "password": password
    }

    response = requests.post(url, headers=headers, data=data)

    if response.status_code == 200:
        print(f"Password '{password}' is correct!")
    else:
        print(f"Password '{password}' is incorrect.")

def generate_password(length):
    characters = string.ascii_letters + string.digits + string.punctuation
    password = ''.join(random.choice(characters) for i in range(length))
    return password

def main():
    password_length = 8
    password = generate_password(password_length)

    test_password(password)

